// Este Function node recibe items que contienen en item.json.output
// con la cadena que queremos limpiar y escapar.

return items.map(item => {
  const originalText = item.json.output;

  // 1. Limpiezas iniciales:
  let cleaned = originalText
    // Quitar etiquetas HTML
    .replace(/<[^>]+>/g, '')
    // Saltos de línea a espacio
    .replace(/\r?\n|\r/g, ' ')
    // Tabs a espacio
    .replace(/\t+/g, ' ')
    // Mantener sólo letras, números, signos básicos y espacios
    .replace(/[^\p{L}\p{N}.,;:¿?!()\s]+/gu, ' ')
    // Normalizar múltiples espacios
    .replace(/\s+/g, ' ')
    // Quitar espacios al inicio y al final
    .trim();

  // 2. Escapado para JSON: primero barras invertidas, luego comillas y control chars
  cleaned = cleaned
    .replace(/\\/g, '\\\\')    // escapamos backslashes
    .replace(/"/g, '\\"')      // escapamos comillas dobles
    .replace(/\r/g, '\\r')     // carriage returns
    .replace(/\n/g, '\\n')     // newlines
    .replace(/\t/g, '\\t');    // tabs

  return {
    output: cleaned
  };
});

